tool.command:
@LINK_BAM@ && @LINK_VARIANTS@
mkdir -p output_dir &&
wasp2-map make-reads input.bam $variant_file --samples '$samples' --out_dir output_dir --out_json wasp_data.json $indels --threads \${GALAXY_SLOTS:-1} --max-indel-len $advanced.max_indel_len --max-seqs $advanced.max_seqs --insert-qual $advanced.insert_qual
